const linkedin = $json.platforms?.linkedin ?? $json.linkedin ?? {};
const text = linkedin.text;
const authorUrn = linkedin.authorUrn;

if (typeof text !== 'string' || text.trim().length === 0) {
  throw new Error('LinkedIn text is required');
}
if ([...text].length > 3000) {
  throw new Error('LinkedIn text exceeds 3000 characters');
}
if (typeof authorUrn !== 'string' || !/^urn:li:(person|organization):/.test(authorUrn)) {
  throw new Error('LinkedIn authorUrn must be a person or organization URN');
}

return [{ json: {
  ...$json,
  linkedin: {
    text,
    authorUrn
  }
} }];

