const previous = $('Prepare LinkedIn post').first().json;
const response = $json;
const headers = response.headers ?? {};
const body = response.body ?? response;
const id = headers['x-restli-id'] ?? headers['X-RestLi-Id'] ?? body.id;

if (typeof id !== 'string' || id.length === 0) {
  throw new Error('LinkedIn did not return a post ID');
}

return [{ json: {
  ok: true,
  platform: 'linkedin',
  id,
  authorUrn: previous.linkedin.authorUrn
} }];
